INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (1038,235790,8,'nevo-a',NULL,'A strong recommendation as both are beloved romantic comedies that balance humor with genuine emotional sweetness.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (1038,300229,5,'nevo-a',NULL,'Though both are widely loved 2000s hits with romance, Shrek leans heavily into satirical animation rather than traditional rom-com tropes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (1038,321213,9,'nevo-a',NULL,'An excellent pairing of early 2000s romantic comedies dealing with women reassessing their pasts and hometown roots.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (1038,328272,6,'nevo-a',NULL,'Both are feel-good movies from 2004, but The Terminal is a contained dramedy rather than a classic romantic comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (1038,367149,1,'nevo-a',NULL,'A terrible recommendation; a lighthearted teen rom-com shares no thematic or stylistic DNA with a sweeping martial arts epic.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (9795,32178,10,'nevo-a',NULL,'A perfect pairing. Both are quintessential Disney Renaissance animated musicals with themes of romance and breaking societal molds.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (9795,36694,6,'nevo-a',NULL,'Though both feature protagonists dealing with magically altered circumstances, Big is a live-action 80s movie while Aladdin is pure 90s animation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (9795,143526,9,'nevo-a',NULL,'Highly recommended. Both are classic Disney animations featuring mythic heroes, vibrant musical numbers, and hilarious magical sidekicks.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (9795,170522,5,'nevo-a',NULL,'Though both are 90s family films involving magical elements unleashed from ancient artifacts, Jumanji\'s darker, live-action tone makes it a moderate fit.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (9795,191246,10,'nevo-a',NULL,'Essential viewing for fans of Aladdin. Both represent the absolute peak of 90s Disney animation with iconic soundtracks and heroic journeys.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (9795,337166,8,'nevo-a',NULL,'While one is traditional 2D fantasy and the other 3D modern adventure, both deliver masterful family-friendly storytelling and humor.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (10916,20371,4,'nevo-a',NULL,'Though both are late-90s sci-fi set in space, Armageddon is an upbeat blockbuster disaster film, contrasting sharply with Alien\'s grim horror.');
