INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (10916,214755,5,'nevo-a',NULL,'A moderate recommendation. Both are dark sci-fi thrillers, but Minority Report is a cerebral mystery while Alien is a visceral monster movie.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (10916,301391,6,'nevo-a',NULL,'Both feature hostile alien encounters, but Signs builds slow-burn suspense on Earth, unlike Resurrection\'s chaotic space action.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (10916,311037,2,'nevo-a',NULL,'A poor pairing. A gory, pessimistic sci-fi horror sequel has almost nothing in common with a bright, heroic comic book origin story.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (10920,262645,9,'nevo-a',NULL,'An excellent recommendation. Both are defining 80s sci-fi action classics featuring heavily armed squads facing terrifying extraterrestrial threats.');
