INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (20371,207989,5,'nevo-a',NULL,'Though both are massive CGI-heavy action blockbusters, Matrix Reloaded\'s dense lore contrasts with Armageddon\'s straightforward disaster thrills.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (20371,207991,4,'nevo-a',NULL,'A weak recommendation. Revolutions is a bleak, lore-heavy war movie, missing the fun and emotional pop-appeal of Armageddon.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (20371,207992,6,'nevo-a',NULL,'Both were massive late-90s hits, but The Matrix redefined sci-fi action whereas Armageddon is purely explosive pop-corn entertainment.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (20371,214755,4,'nevo-a',NULL,'Though both star major A-listers in sci-fi settings, Minority Report\'s moody, cerebral neo-noir tone doesn\'t fit Armageddon\'s Michael Bay explosions.');
