INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (27168,207157,6,'nevo-a',NULL,'Both are high-energy mid-90s hits, but Bad Boys is an R-rated buddy cop action film while The Mask is a hyperactive supernatural comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (27168,276217,5,'nevo-a',NULL,'Though both deal with criminals and cops, Reservoir Dogs is a tense, dialogue-driven indie thriller, lacking the glossy explosions of Bad Boys.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (27168,340799,8,'nevo-a',NULL,'A great pairing of 90s action-comedies. Both feature charismatic leads balancing massive set pieces with sharp humor.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (32178,191246,10,'nevo-a',NULL,'A flawless recommendation. Both are the crown jewels of 90s Disney animation, featuring Broadway-level music and deep emotional resonance.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (32178,337166,8,'nevo-a',NULL,'Both revolutionized family entertainment in the 90s, offering universally appealing stories, even if the animation styles differ.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (39551,185628,7,'nevo-a',NULL,'Both are epic, violent war films from the early 2000s, though they differ greatly in era and their focus on modern tactics vs historical romanticism.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (39551,250746,6,'nevo-a',NULL,'A moderate fit. While both are brutal depictions of warfare, The Patriot is heavily melodramatic compared to the documentary-like grit of Black Hawk Down.');
