INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (39551,289109,10,'nevo-a',NULL,'An outstanding recommendation. Both are visceral, highly realistic portrayals of the chaos and brotherhood of intense military combat.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (39551,330388,5,'nevo-a',NULL,'Though both are acclaimed war films, The Thin Red Line is a slow, philosophical meditation on nature and death, contrasting Black Hawk Down\'s kinetic action.');
