INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (39551,340652,6,'nevo-a',NULL,'Both feature massive ensemble casts in chaotic battles, but Troy\'s mythical swords-and-sandals epic feels very different from modern urban warfare.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (39551,360480,9,'nevo-a',NULL,'A very strong pairing. Both are intense, tactical portrayals of soldiers trapped in brutal, unrelenting combat scenarios.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (40226,113305,5,'nevo-a',NULL,'Both are defining 2000s horror films, but they appeal to different tastes: grounded found-footage realism versus elaborate, supernatural Rube Goldberg deaths.');
