INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (40226,291221,4,'nevo-a',NULL,'Though both revolutionized 90s horror, Scream\'s meta-humor and slick production clash with Blair Witch\'s ultra-realistic, low-budget grit.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (40226,301391,6,'nevo-a',NULL,'Both expertly use what you *don\'t* see to build tension, but Signs is a polished studio thriller while Blair Witch is raw independent horror.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,45129,10,'nevo-a',NULL,'The perfect recommendation. A direct sequel that maintains the gritty, kinetic espionage style and deepens the protagonist\'s journey.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,79716,3,'nevo-a',NULL,'A poor pairing. Grounded, hand-to-hand spy thriller versus a massive CGI global weather disaster movie.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,101070,9,'nevo-a',NULL,'Highly recommended. Both are intense, paranoid thrillers about men on the run using their wits against massive government surveillance.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,107166,6,'nevo-a',NULL,'Though both are action-heavy thrillers about identity, Face/Off is absurdly theatrical while Bourne is defined by its grounded realism.');
