INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,214755,7,'nevo-a',NULL,'Both feature highly capable men on the run from the systems they used to serve, though one relies on sci-fi concepts.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,278498,2,'nevo-a',NULL,'A completely mismatched recommendation between a grounded action thriller and a supernatural horror film.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,301391,3,'nevo-a',NULL,'Though both are thrilling, Signs is a slow-burn alien invasion movie that offers nothing to a fan looking for martial arts and car chases.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,303564,4,'nevo-a',NULL,'While both feature great twists, a quiet supernatural drama does not fit the profile of a fast-paced espionage action fan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45128,350424,4,'nevo-a',NULL,'Though both involve mysteries of the mind, Vanilla Sky is a surreal psychological drama, lacking the spy-thriller action of Bourne.');
