INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,112290,5,'nevo-a',NULL,'A moderate link at best; both feature unstable protagonists, but the genres (action vs dark satire) are wildly different.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,113305,1,'nevo-a',NULL,'A terrible recommendation. Fans of kinetic hand-to-hand combat spy thrillers aren\'t necessarily looking for supernatural teen death setups.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,139653,2,'nevo-a',NULL,'Completely disconnected genres. A dark espionage sequel shares no DNA with a magical British boarding school fantasy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,163715,7,'nevo-a',NULL,'A fun, solid recommendation. Both are slick, globe-trotting action films featuring elaborate car chases and capable professionals.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,176712,6,'nevo-a',NULL,'Both feature relentless assassins hunting down their former handlers, but Tarantino\'s stylized dialogue contrasts with Bourne\'s breathless realism.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,185628,4,'nevo-a',NULL,'A weak pairing. A historical epic about samurai culture does not scratch the itch for a modern, shaky-cam spy thriller.');
