INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,214755,7,'nevo-a',NULL,'A good fit. Both are intense, propulsive thrillers about framed men staying one step ahead of advanced tracking systems.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,278498,2,'nevo-a',NULL,'No crossover appeal here. Espionage action fans are not inherently looking for slow-burn J-horror remakes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,301391,3,'nevo-a',NULL,'A bad recommendation. A suspenseful farmhouse alien invasion movie shares no stylistic similarities with a European car chase thriller.');
