INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (45129,331427,5,'nevo-a',NULL,'Both are action-oriented and cynical about government/military institutions, but Three Kings is highly satirical while Bourne is dead serious.');
