INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (46169,330388,4,'nevo-a',NULL,'Though both are war epics, it is a bad recommendation since Thin Red Line is a slow, poetic meditation, unlike Braveheart\'s crowd-pleasing heroism.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (46169,331427,3,'nevo-a',NULL,'A major stylistic clash. A sweeping 13th-century Scottish epic has nothing in common with a cynical, modern Gulf War heist.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48075,300229,7,'nevo-a',NULL,'Both are massive, highly quotable early 2000s comedies that blend fantasy concepts with mainstream, crowd-pleasing humor.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,56729,2,'nevo-a',NULL,'A terrible recommendation. A classic, well-crafted Pixar animation shares nothing with a critically panned, chaotic live-action adaptation.');
