INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,143526,8,'nevo-a',NULL,'Both are highly entertaining 90s animated films full of colorful characters and protagonists trying to prove their worth as heroes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,170522,5,'nevo-a',NULL,'Though both are 90s family films involving bugs/animals, Jumanji is much darker and live-action, making it only a moderate fit.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,191246,8,'nevo-a',NULL,'Both are top-tier 90s animations about animals overcoming tyrannical rulers to save their communities.');
