INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,222112,7,'nevo-a',NULL,'Both are excellent late-90s animated films about an underdog using their unique wits to save their people against a terrifying army.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,290939,3,'nevo-a',NULL,'A weak pairing. A carefully crafted Pixar story does not translate well to a goofy, early 2000s live-action cartoon adaptation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,300229,8,'nevo-a',NULL,'Both are seminal CG-animated films from the era, though Shrek leans much heavier into satirical pop-culture references.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,312150,4,'nevo-a',NULL,'While both are family-friendly, Spy Kids\' manic live-action gadgetry is a completely different vibe from Pixar\'s grounded storytelling.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,325098,7,'nevo-a',NULL,'Both are visually stunning late-90s animations exploring the clash between the natural world and civilized/colonizing forces.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,337166,10,'nevo-a',NULL,'The perfect recommendation. The first two Pixar movies share the same DNA of breathing life into the secret worlds of tiny beings.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (48950,337168,10,'nevo-a',NULL,'Just like the original Toy Story, this offers the same incredible Pixar blend of humor, heart, and stunning early CG animation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,113504,3,'nevo-a',NULL,'Despite both being for kids, one is a manic, widely disliked live-action film and the other is a heartfelt Pixar masterpiece.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,139650,3,'nevo-a',NULL,'A poor recommendation. The chaotic absurdity of Cat in the Hat clashes entirely with the earnest, structured magical world of Harry Potter.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,139652,2,'nevo-a',NULL,'A terrible fit. Goblet of Fire is a dark, mature fantasy thriller, completely disconnected from a loud, neon children\'s comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,139653,2,'nevo-a',NULL,'No shared audience appeal here. A deeply emotional and dark wizarding movie vs a hyperactive Dr. Seuss adaptation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,139654,2,'nevo-a',NULL,'Completely different tones, genres, and quality levels. Not recommended.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,139655,2,'nevo-a',NULL,'Alfonso Cuaron\'s moody, cinematic fantasy masterpiece shares absolutely nothing with this chaotic comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,139657,4,'nevo-a',NULL,'Both are early 2000s children\'s adaptations, but Potter is an earnest classic while Cat in the Hat relies on crass adult humor.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,158927,3,'nevo-a',NULL,'A masterpiece of animated superhero storytelling vs a loud live-action failure. A bad recommendation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,199255,6,'nevo-a',NULL,'A reasonable recommendation. Both are loud, colorful, hyperactive mid-2000s comedies aimed squarely at young children.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,218415,4,'nevo-a',NULL,'While both feature furry chaotic creatures entering children\'s lives, Pixar\'s emotional depth is entirely missing from Cat in the Hat.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,222112,3,'nevo-a',NULL,'A sweeping animated epic of war and honor has no thematic connection to a bizarre, contained house comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,256631,4,'nevo-a',NULL,'Though both have eccentric Johnny Depp-esque performances, Pirates is a grand blockbuster adventure, not a contained slapstick comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,256632,4,'nevo-a',NULL,'The swashbuckling adventure and genuine thrills of Pirates do not align with the neon-soaked chaos of this Dr. Seuss adaptation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,290939,8,'nevo-a',NULL,'An excellent pairing. Both are early 2000s live-action adaptations of beloved cartoons that rely heavily on CGI and crude humor.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,300229,5,'nevo-a',NULL,'Both rely on pop-culture references and gross-out humor, but Shrek executes its satire brilliantly while Cat in the Hat fails.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,300230,5,'nevo-a',NULL,'Like the first Shrek, this is a much better-executed version of the anarchic, adult-leaning kids comedy that Cat in the Hat tried to be.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,312150,7,'nevo-a',NULL,'Both are bizarre, highly stylized, hyperactive early 2000s kids movies with very weird CGI.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56729,337168,2,'nevo-a',NULL,'A deeply emotional and perfectly crafted animated sequel shares nothing with this jarring live-action mess.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,63823,3,'nevo-a',NULL,'A terrible recommendation. A breezy, jazzy Spielberg caper has absolutely nothing in common with a hyper-violent Brazilian favela crime epic.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,112290,4,'nevo-a',NULL,'Though both feature protagonists living double lives, Catch Me If You Can is fun and charming, while Fight Club is aggressive and cynical.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,164572,6,'nevo-a',NULL,'Both are slick, retro-styled crime capers focusing on clever criminals outsmarting the authorities, though Tarantino\'s film is much grittier.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,182955,6,'nevo-a',NULL,'Both are excellent period pieces dealing with crime and police work, but L.A. Confidential is a dark, bloody noir compared to Spielberg\'s light tone.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,214755,7,'nevo-a',NULL,'A good pairing of 2002 Spielberg films. Both feature incredible pacing and center on a relentless detective hunting a fleeing man.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,224842,3,'nevo-a',NULL,'A poor fit. Mystic River is a devastating, grim tragedy about trauma and murder, completely lacking the fun escapism of this caper.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (56871,337404,4,'nevo-a',NULL,'While both deal with law enforcement, Traffic is a bleak, documentary-style look at the drug war, unlike this glossy, fun biography.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (63823,112290,7,'nevo-a',NULL,'Both are hyper-kinetic, visually groundbreaking, and deeply cynical late-90s/early-2000s films dealing with toxic masculinity and violence.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (63823,164572,5,'nevo-a',NULL,'Though both involve crime and drugs, Jackie Brown\'s slow, deliberate pacing contrasts sharply with the frantic, raw energy of City of God.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (63823,182955,6,'nevo-a',NULL,'Both are sweeping, multi-character epics about deep-rooted systemic corruption and violence, though City of God is far more chaotic.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (63823,214755,4,'nevo-a',NULL,'A weak link. A glossy, high-concept Tom Cruise sci-fi thriller doesn\'t match the raw, street-level realism of the favelas.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (63823,224842,6,'nevo-a',NULL,'Both are incredibly bleak, tragic explorations of how childhood environments of violence inescapably shape adult destinies.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (63823,337404,8,'nevo-a',NULL,'A very strong recommendation. Both offer sprawling, gritty, documentary-style looks at the devastating effects of the drug trade on society.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (72559,112290,5,'nevo-a',NULL,'Though both are mid-90s films designed to provoke audiences with themes of alienation and violence, they tackle them in very different ways.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (72559,214755,3,'nevo-a',NULL,'A bizarre, sterile erotic thriller about car crashes shares no DNA with a blockbuster Spielberg sci-fi chase movie.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,155070,7,'nevo-a',NULL,'Both are peak 2004 CGI blockbusters featuring massive, city-destroying spectacles and a lone hero trying to warn everyone of the impending doom.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,176712,2,'nevo-a',NULL,'A terrible recommendation. A stylized martial arts revenge film has nothing to offer a fan looking for weather-based disaster porn.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,207989,6,'nevo-a',NULL,'Both are massive, CGI-heavy early 2000s spectacles, but Reloaded is dense with sci-fi philosophy rather than simple disaster thrills.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,207991,5,'nevo-a',NULL,'While both feature the apocalyptic destruction of humanity, Revolutions is a grim sci-fi war movie, lacking the fun popcorn vibe of a disaster film.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,207992,5,'nevo-a',NULL,'Both feature high-concept threats to humanity, but The Matrix is a masterclass in cyberpunk action, not a Roland Emmerich disaster film.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,214755,5,'nevo-a',NULL,'Though both are big-budget 2000s sci-fi, Minority Report is a complex mystery rather than a straightforward survival spectacle.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,301391,6,'nevo-a',NULL,'Both deal with massive global phenomena threatening families, but Signs builds quiet, slow-burn tension rather than relying on CGI destruction.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,311037,7,'nevo-a',NULL,'Both are classic, incredibly successful early 2000s popcorn blockbusters characterized by massive special effects and earnest heroism.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,311038,6,'nevo-a',NULL,'Like the first Spider-Man, this is great 2000s spectacle, though Spider-Man 2\'s deep character work outshines standard disaster movie tropes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (79716,350424,2,'nevo-a',NULL,'No connection. A massive global freezing disaster movie vs an intimate, surreal psychological romance.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (81776,214755,5,'nevo-a',NULL,'Both are serious, somewhat somber sci-fi films, but Deep Impact is an ensemble disaster movie while Minority Report is a focused neo-noir chase.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (81776,301391,7,'nevo-a',NULL,'A solid pairing. Both are late 90s/early 2000s sci-fi films that focus more on the emotional, human reaction to a global apocalyptic threat than just explosions.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (81776,350424,3,'nevo-a',NULL,'A weak recommendation. An apocalyptic comet movie has very little in common with a surreal exploration of a rich man\'s dreams and regrets.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (90772,214755,6,'nevo-a',NULL,'Both are dark, complex sci-fi films involving determinism and predicting the future, though Donnie Darko is far more indie and surreal.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (90772,301391,7,'nevo-a',NULL,'Both are moody, atmospheric early 2000s films dealing with sci-fi elements (time travel/aliens) intruding on quiet suburban life.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (90772,350424,8,'nevo-a',NULL,'An excellent pairing. Both are highly surreal, mind-bending early 2000s psychological thrillers exploring reality, dreams, and fatalism.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (96593,313459,9,'nevo-a',NULL,'A fantastic pairing. Both are foundational John Williams-scored masterpieces of late 70s/early 80s sci-fi that defined modern blockbuster magic.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (96593,313478,8,'nevo-a',NULL,'While Empire is much darker than E.T., both are absolute pinnacles of emotional, practical-effects-driven sci-fi storytelling.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (96593,313479,8,'nevo-a',NULL,'A strong recommendation. Jedi shares a lot of E.T.\'s emotional warmth and family-friendly puppet creatures (Ewoks).');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (101070,107166,7,'nevo-a',NULL,'Both are absolutely peak late-90s action thrillers, blending high concepts, huge set pieces, and massive star power.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (101070,214755,9,'nevo-a',NULL,'A perfect thematic match. Both are propulsive, paranoid thrillers about an innocent man framed and hunted by an omniscient surveillance system.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (101070,280115,8,'nevo-a',NULL,'An excellent recommendation. Both are high-octane 90s Jerry Bruckheimer blockbusters full of government conspiracies and explosions.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (101070,342685,5,'nevo-a',NULL,'Though both are massive 90s hits, a paranoid surveillance spy thriller offers a very different experience than a weather disaster movie.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (101418,251477,6,'nevo-a',NULL,'Both are sweeping, melodramatic World War II romances revolving around tragic love triangles, though their critical reception differs wildly.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (104338,106988,8,'nevo-a',NULL,'Both are incredibly inventive, visually unique, and deeply romantic indie films dealing with introverted characters finding love.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (104338,235790,4,'nevo-a',NULL,'A weak pairing. While both are romances, Eternal Sunshine\'s surreal melancholy completely clashes with Notting Hill\'s traditional, breezy formula.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (104338,307274,7,'nevo-a',NULL,'Both are slow, deeply melancholic sci-fi films that use high-concept premises to explore grief, memory, and doomed relationships.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (104338,321213,2,'nevo-a',NULL,'A terrible recommendation. A surreal, depressing masterpiece of memory erasure has nothing in common with a fluffy southern rom-com.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (104338,328272,4,'nevo-a',NULL,'Though both are 2004 films with romance, The Terminal\'s quirky, uplifting tone does not match the devastating emotional weight of Eternal Sunshine.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (104338,350424,9,'nevo-a',NULL,'A brilliant pairing. Both are mind-bending, surreal explorations of love, regret, and the manipulation of memory and reality.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (106988,235790,6,'nevo-a',NULL,'Both are sweet, feel-good romantic comedies, though Amelie\'s quirky French arthouse style is very different from British commercial rom-coms.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (106988,321213,3,'nevo-a',NULL,'A very weak link. A visually inventive French cinema classic does not appeal to the same sensibilities as a formulaic American rom-com.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (106988,328272,7,'nevo-a',NULL,'Both are deeply charming, quirky films focused on kind-hearted outsiders finding magic and connection in enclosed, structured worlds.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (107166,214755,6,'nevo-a',NULL,'Both are action-heavy thrillers involving altered identities, but Face/Off is glorious absurd camp, whereas Minority Report is serious neo-noir.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (107166,280115,10,'nevo-a',NULL,'The ultimate 90s action pairing. Both star Nicolas Cage in unhinged, explosive masterpieces of peak 90s cinematic excess.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (107166,342685,6,'nevo-a',NULL,'Both are massive, loud 90s blockbusters, but an absurd Hong-Kong-style shootout movie is very different from chasing tornadoes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (109093,112290,6,'nevo-a',NULL,'Both are darkly comedic, highly cynical 90s classics that dissect the failures of modern men, though their cinematic styles are entirely different.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (109093,164572,8,'nevo-a',NULL,'A fantastic pairing. Both are masterful 90s crime films that rely on sharp, crackling dialogue and characters making a mess of simple criminal plans.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (109093,182955,7,'nevo-a',NULL,'Both are incredible crime/detective films, but Fargo\'s quirky Midwestern black comedy contrasts heavily with L.A. Confidential\'s slick, serious noir.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (109093,337404,5,'nevo-a',NULL,'While both deal with crime, Traffic\'s sprawling, documentary-like seriousness lacks the idiosyncratic, absurd black humor of Fargo.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,113305,3,'nevo-a',NULL,'A poor recommendation. A biting philosophical satire on consumerism and masculinity shares no ground with a supernatural teen slasher.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,164572,5,'nevo-a',NULL,'Both are defining 90s films by iconic directors, but Jackie Brown\'s slow, mature pacing is the opposite of Fight Club\'s manic, aggressive editing.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,182955,6,'nevo-a',NULL,'Both feature complex narratives and violent masculinity, but a classic 50s noir doesn\'t match the anti-establishment grunge of Fight Club.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,210511,9,'nevo-a',NULL,'An excellent pairing. Both are gritty, mind-bending thrillers featuring unreliable narrators and incredible, reality-shattering twist endings.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,214755,6,'nevo-a',NULL,'Both feature protagonists questioning their reality and fighting corrupt systems, but Minority Report is much more traditional blockbuster sci-fi.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,224842,5,'nevo-a',NULL,'Both are very dark films dealing with trauma, but Mystic River is a grounded, somber tragedy rather than a stylish, kinetic satire.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,278498,3,'nevo-a',NULL,'A bad match. A psychological satire about modern masculinity has nothing in common with a slow-burn supernatural horror film.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,301391,4,'nevo-a',NULL,'Both have huge twists, but an intimate movie about an alien invasion and faith does not appeal to the same aggressive energy as Fight Club.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,303564,7,'nevo-a',NULL,'Both are the defining \'twist-ending\' movies of 1999 centering on a protagonist completely misunderstanding his own reality.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,337404,5,'nevo-a',NULL,'Though both are gritty and critically acclaimed, Traffic\'s realistic docu-drama style lacks the stylized, punk-rock energy of Fight Club.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,348944,8,'nevo-a',NULL,'A great recommendation. Both are dark, stylized 90s crime thrillers heavily reliant on an iconic, reality-altering twist ending.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112290,350424,7,'nevo-a',NULL,'Both feature deeply unreliable protagonists who slowly realize their entire reality is an illusion constructed by their own minds.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,154309,8,'nevo-a',NULL,'A very logical pairing. Both are textbook late-90s/early-2000s teen slashers focusing on a group of doomed, attractive high schoolers.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,182955,2,'nevo-a',NULL,'Terrible recommendation. A supernatural teen gore-fest shares absolutely nothing with a prestige 1950s detective noir.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,210511,4,'nevo-a',NULL,'Though both deal with death, Memento is a brilliant, complex neo-noir, whereas Final Destination is straightforward popcorn horror.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,214755,5,'nevo-a',NULL,'Both nominally deal with characters trying to change a predetermined fatal future, but the genres (teen horror vs prestige sci-fi) are totally mismatched.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,278498,7,'nevo-a',NULL,'Both are iconic early 2000s horror films revolving around a deadly curse with a strict time limit that protagonists must solve to survive.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,291221,8,'nevo-a',NULL,'A strong recommendation. Both are seminal teen horrors of the era, relying on clever meta-rules to dispatch a cast of young actors.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,301391,4,'nevo-a',NULL,'Both build suspense, but Signs is a quiet, faith-based alien movie, far removed from the elaborate, bloody death traps of Final Destination.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,303564,5,'nevo-a',NULL,'Though both are supernatural films involving death, Sixth Sense is a quiet, emotional drama, not an inventive slasher.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113305,350424,3,'nevo-a',NULL,'No crossover appeal here. A fun, gory teen movie vs a surreal, slow-paced Tom Cruise psychological drama.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,124160,2,'nevo-a',NULL,'A terrible pairing. Finding Nemo is a brilliant, emotionally profound Pixar film; Garfield is a lazy, critically panned live-action cash grab.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,139652,5,'nevo-a',NULL,'Though both are massive 2000s family hits, Goblet of Fire is a very dark, mature fantasy, contrasting Nemo\'s bright aquatic adventure.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,158927,10,'nevo-a',NULL,'The perfect recommendation. Both represent the absolute golden era of Pixar, offering incredible animation, deep emotional cores, and perfect pacing.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,199255,7,'nevo-a',NULL,'Both are massive 2000s CGI animations about zoo/aquarium animals trying to navigate the wild, though Madagascar is much sillier.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,218415,10,'nevo-a',NULL,'An elite Pixar pairing. Both are incredibly heartfelt, funny stories centered around the profound bond between an adult figure and a child.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,222112,7,'nevo-a',NULL,'Both are excellent, emotionally resonant animated films about family expectations, but Mulan\'s war setting is very different from Nemo\'s ocean.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,290939,3,'nevo-a',NULL,'A weak recommendation. An emotionally rich Pixar masterpiece has nothing to do with a goofy, live-action cartoon adaptation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,300229,8,'nevo-a',NULL,'Both dominated the early 2000s animation landscape, though Shrek relies on edgy satire while Nemo relies on genuine emotional stakes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,300230,8,'nevo-a',NULL,'Like the first Shrek, a titan of 2000s animation. Fans of high-quality family entertainment will love both, despite tone differences.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,312150,4,'nevo-a',NULL,'While both are family films involving kids in peril, Spy Kids is a chaotic, hyperactive live-action film compared to Nemo\'s serene beauty.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,325098,7,'nevo-a',NULL,'Both are beautiful, family-oriented animated films that heavily focus on themes of parenting, loss, and the dangers of the natural world.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,337168,10,'nevo-a',NULL,'Another flawless Pixar recommendation. Both are masterclasses in animated storytelling, balancing hilarious side characters with deep emotional themes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (124160,158927,2,'nevo-a',NULL,'A very bad pairing. One is a lazy, poorly-written live action movie with a CGI cat, the other is an animated superhero masterpiece.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (124160,199255,6,'nevo-a',NULL,'A reasonable recommendation. Both are mid-2000s comedies aimed at very young kids, featuring sarcastic talking CGI animals.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (124160,218415,3,'nevo-a',NULL,'Pixar\'s brilliant, emotional storytelling is completely absent in Garfield. They only share the \'kids movie\' label.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (124160,300229,5,'nevo-a',NULL,'Both feature sarcastic, cynical CGI protagonists, but Shrek is a genuinely clever and funny film, while Garfield falls flat.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (124160,300230,5,'nevo-a',NULL,'Again, Shrek 2 executes the sarcastic CGI animal comedy perfectly, making it a frustrating recommendation for a Garfield fan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (124160,337168,2,'nevo-a',NULL,'A terrible recommendation bridging a critically panned cash-grab and one of the greatest animated sequels ever made.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,139652,8,'nevo-a',NULL,'A strong franchise recommendation, though Goblet of Fire is significantly darker and more mature than the whimsical Chamber of Secrets.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,139654,8,'nevo-a',NULL,'A natural continuation of the series, moving from the mystery-solving of year two to the full-blown rebellion of year five.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,139655,9,'nevo-a',NULL,'The perfect next step. Azkaban takes the foundation built in Chamber of Secrets and elevates it with masterful, moody direction.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,139657,10,'nevo-a',NULL,'A flawless recommendation. These first two films share the exact same director, whimsical tone, and magical, family-friendly atmosphere.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,199255,4,'nevo-a',NULL,'A weak pairing. A sprawling, slightly dark British magical mystery shares no themes with a slapstick CGI animal comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,290939,5,'nevo-a',NULL,'Both are 2002 kids\' films revolving around solving mysteries with supernatural elements, but Potter is far superior in quality.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,300229,6,'nevo-a',NULL,'Both are massive early 2000s fantasy hits, but Shrek mocks the fantasy tropes that Harry Potter plays completely straight.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139650,300230,6,'nevo-a',NULL,'Like the first Shrek, a fun fantasy-adjacent movie, but tonally very different from the earnest wonder of the Wizarding World.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,139653,9,'nevo-a',NULL,'An excellent franchise pairing. Both deal with dark, impending war and the awkward, hormone-filled teenage romances of the main trio.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,139654,10,'nevo-a',NULL,'The perfect sequential recommendation. Phoenix deals directly with the traumatizing fallout of Goblet of Fire\'s climax.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,139655,9,'nevo-a',NULL,'Both films mark the turning point in the series where it abandons childhood whimsy for dark, mature, and dangerous themes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,139657,6,'nevo-a',NULL,'Though in the same franchise, it is a moderate recommendation; the first movie\'s innocent joy clashes wildly with the death and terror in movie four.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,158927,6,'nevo-a',NULL,'Both are excellent mid-2000s family action films dealing with coming of age and responsibility, but exist in completely different genres.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,199255,3,'nevo-a',NULL,'A poor recommendation. A dark, intense movie featuring the murder of a teenager does not pair well with dancing CGI lemurs.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,218415,5,'nevo-a',NULL,'While both are great, a heavy, emotional fantasy thriller is a jarring shift from a heartfelt, colorful Pixar comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,256631,8,'nevo-a',NULL,'A great pairing. Both are massive mid-2000s blockbuster sequels that take their fantasy worlds into significantly darker, scarier territory.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,256632,8,'nevo-a',NULL,'Both are thrilling, slightly scary live-action fantasy blockbusters that dominated the 2000s pop culture landscape.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,290939,2,'nevo-a',NULL,'A terrible recommendation. The dark, prestige fantasy of Goblet of Fire has nothing to do with this goofy live-action cartoon.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,300229,5,'nevo-a',NULL,'Though both involve dragons and fantasy, Shrek is a comedy roasting the genre, while Harry Potter is a serious, dramatic entry.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,300230,5,'nevo-a',NULL,'A moderate fit. Both are 2004 fantasy sequels, but one is a hilarious satire and the other is a grim thriller.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,312150,3,'nevo-a',NULL,'A weak pairing. Spy Kids\' manic, low-budget silliness contrasts sharply with the sweeping, expensive epic scale of Harry Potter.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,139654,9,'nevo-a',NULL,'An excellent franchise pairing. Both deal with the dark, oppressive political reality of Voldemort\'s return and Dumbledore\'s army.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,139655,8,'nevo-a',NULL,'Both are the most visually moody and stylistically dark entries in the Potter series, focusing heavily on character drama over action.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,158927,5,'nevo-a',NULL,'Though both are great films, the bleak, almost suffocating darkness of Half-Blood Prince clashes with Pixar\'s bright superhero fun.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,163715,3,'nevo-a',NULL,'A bad recommendation. A sleek, modern heist film involving Mini Coopers has no connection to a grim British wizarding movie.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,194500,9,'nevo-a',NULL,'A fantastic recommendation. Both are massive, deeply emotional fantasy epics dealing with the heavy burden of fighting an ultimate evil.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,199255,2,'nevo-a',NULL,'A terrible pairing. There is absolutely no crossover appeal between a tragic fantasy about impending war and dancing cartoon animals.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,256631,7,'nevo-a',NULL,'Both are dark, sprawling mid-2000s fantasy blockbusters that end on massive, tragic cliffhangers.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,256632,6,'nevo-a',NULL,'Though both are major fantasy franchises, Pirates is much more swashbuckling and fun, lacking the bleak sorrow of this Potter entry.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,300230,4,'nevo-a',NULL,'A weak recommendation. A hilarious fairytale spoof does not fit the mood of a viewer watching the darkest Harry Potter movie.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139653,311038,7,'nevo-a',NULL,'Both are brilliant sequels that heavily focus on the agonizing personal sacrifices the heroes must make for the greater good.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139654,139655,9,'nevo-a',NULL,'A very strong pairing. Both films focus heavily on Sirius Black, themes of depression (Dementors), and rebellion against authority.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139654,199255,2,'nevo-a',NULL,'An awful recommendation. A movie about teenagers suffering PTSD and political corruption does not pair with a goofy zoo animal comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139654,290939,2,'nevo-a',NULL,'Completely disconnected in tone, quality, and theme. A serious fantasy thriller vs a badly-aged live-action cartoon.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139654,300230,4,'nevo-a',NULL,'While both are excellent mid-2000s sequels, their tones are wildly incompatible (grim teenage rebellion vs pop-culture satire).');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,139657,7,'nevo-a',NULL,'A moderate franchise recommendation; while it\'s the same world, Cuaron\'s dark, moody Azkaban feels like a completely different genre than Columbus\'s bright original.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,199255,3,'nevo-a',NULL,'A poor fit. A stylized, slightly terrifying cinematic masterpiece shares nothing with a standard animated comedy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,290939,3,'nevo-a',NULL,'Both feature solving supernatural mysteries with a dog, but the tone and cinematic quality couldn\'t be further apart.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,300229,5,'nevo-a',NULL,'Both are widely acclaimed fantasy films of the era, but Shrek\'s irony contrasts with Azkaban\'s sincere, moody coming-of-age story.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,300230,5,'nevo-a',NULL,'Both are peak 2004 fantasy sequels that outshine their predecessors, though they exist on opposite ends of the tonal spectrum.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139657,199255,5,'nevo-a',NULL,'Both are very successful, lighthearted 2000s family films, though Potter is much more earnest than Madagascar\'s slapstick.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139657,290939,4,'nevo-a',NULL,'While both are early 2000s kids movies about a group of friends solving supernatural mysteries, Potter\'s quality is vastly superior.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139657,300229,7,'nevo-a',NULL,'Both define the childhood of the early 2000s generation, offering massive fantasy worlds, though Shrek is much more cynical.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139657,300230,7,'nevo-a',NULL,'A solid pairing of massively influential early 2000s family fantasy films, appealing to the exact same demographic.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (140221,300229,4,'nevo-a',NULL,'Though both are acclaimed animated fantasies from 2004, Miyazaki\'s poetic, surreal masterpiece shares no vibe with Shrek\'s crude pop-culture satire.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (143526,170522,6,'nevo-a',NULL,'Both are wildly entertaining 90s family hits, though Hercules is a bright musical comedy and Jumanji is a slightly terrifying live-action adventure.');
